-- Check per-rep breakdown
SELECT cr.rep_id, cr.name, COUNT(l.id) as lead_count
FROM leads l
JOIN company_reps cr ON l.assigned_rep_id = cr.id
GROUP BY cr.rep_id, cr.name
ORDER BY cr.rep_id;

